const Q_ECONOMICS_2020_MODEL_II=[{"id": "objective>Economics>2020 Model II>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A change in demand is caused by all except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">price of other commodity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price of the commodity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">population</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A change in demand is also known as shifts in the demand curve. change or shift in demand  is as a result of changes in other factors affecting demand except price of the commodity, such factors affecting demand are : price of other commodity, income, taste,population etc.</div>", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2020 Model II>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A decrease in demand is caused by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase in consumers income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">effective advertisement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a fall in the price of a substitute</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rising price of substitute</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A decrease in demand occurs when the demand curve shift to the left. The decrease is caused by: <br/> - change in consumer income <br/> - change in taste <br/> - a fall in the price of a substitute <br/> - a rise in the price of a complement</div>", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2020 Model II>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the demand is unitary, total revenue will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase as price increases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease as price increases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases as price decreases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remain constant</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If the demand has unitary elasticity, total revenue is not affected by changes in price since e= 1, then MR= 0.</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>2020 Model II>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the total revenue is represented as OABQ while the total cost is represented as OCDQ. The profit of the monopoly is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ABCD</div>", "<div style=\"font-family:Cambria;font-size:17px;\">OABC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">OQAB</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ABCQ</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Profit is calculated as : TR - TC <br/>                                    = OABQ - OCDQ <br/>                                       = ABCD</div>", "topic": "MARKET STRUCTURE : IMPERFECT MARKET ( MONOPOLY)"}, {"id": "objective>Economics>2020 Model II>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The higher the price of a commodity, the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Lower the supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lower the quantity supplied</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Higher the quantity supplied</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Higher the price</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The second law of demand and supply states that, other things being equal, the higher the price, the greater the quantity that will be supplied.</div>", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2020 Model II>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">For a three sector or closed economy, GNP is calculated as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C+I+G</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C+I+G+ (X-M)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C+I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C+I+G+ (X+M)</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For a three sector or closed economy, Gross National Product (GNP) is calculated as the sum of Consumption (C), Investment (I), and Government spending (G). This is represented by the formula C+I+G. The other options include terms related to exports (X) and imports (M), which are not considered in a three sector economy model.</div>", "topic": "NATIONAL INCOME : CONCEPT"}, {"id": "objective>Economics>2020 Model II>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">SECTOR</td><td style=\"border:1px solid black;text-align:center;\"> AMOUNT(#MILLION)</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Health</td><td style=\"border:1px solid black;text-align:center;\"> 30</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Education</td><td style=\"border:1px solid black;text-align:center;\"> 25</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Housing</td><td style=\"border:1px solid black;text-align:center;\"> 15</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Manufacturing</td><td style=\"border:1px solid black;text-align:center;\"> 10</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Agriculture</td><td style=\"border:1px solid black;text-align:center;\"> 20</td></tr></table></div> <br/> What is the highest sectorial angle of the sector?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">108</div>", "<div style=\"font-family:Cambria;font-size:17px;\">90</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30</div>", "<div style=\"font-family:Cambria;font-size:17px;\">54</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">∅<hr size=\"1\" />100</td><td style=\"text-align:center;\">x 360</td><td style=\"text-align:center;\"></td></tr></table></div> <br/>                   <br/>    <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\"> Health =</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">30<hr size=\"1\" />100</td><td style=\"text-align:center;\">x 360</td><td style=\"text-align:center;\">=108</td></tr></table></div>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\"> Education =</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">25<hr size=\"1\" />100</td><td style=\"text-align:center;\">x 360</td><td style=\"text-align:center;\">=90</td></tr></table></div>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\"> Housing =</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">15<hr size=\"1\" />100</td><td style=\"text-align:center;\">x 360</td><td style=\"text-align:center;\">=54</td></tr></table></div>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\"> Manufacturing =</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">10<hr size=\"1\" />100</td><td style=\"text-align:center;\">x 360</td><td style=\"text-align:center;\">=36</td></tr></table></div>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\"> Agriculture =</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">20<hr size=\"1\" />100</td><td style=\"text-align:center;\">x 360</td><td style=\"text-align:center;\">=72</td></tr></table></div>  <br/>  <br/> The highest sectorial angle is 108 <br/> </div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY"}, {"id": "objective>Economics>2020 Model II>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The value of money is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">directly related to the price level</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inversely related to the price level</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inversely related to the supply of money</div>", "<div style=\"font-family:Cambria;font-size:17px;\">directly related to the demand for money</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The value money can be measured by the use of price index.The value of money is inversely related to the price level.</div>", "topic": "MONEY : VALUE OF MONEY"}, {"id": "objective>Economics>2020 Model II>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An economic condition in which much reduced economic activity co-exists with inflation is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">stagflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost-push inflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">slumpflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inflationary spiral</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Slumpflation is an economic situation or condition in which much reduced economic activity co-exists with inflation i.e idleness and under utilisation of resources such as capital and labour</div>", "topic": "INFLATION & DEFLATION : TYPES"}, {"id": "objective>Economics>2020 Model II>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the long - run, there is no</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Total cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Variable cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Marginal cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fixed cost</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The long-run is also known as planning, envelope cost in which there is no possibilities for expansion. In the long-run all factors of production are completely variable, hence no fixed cost.</div>", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST"}, {"id": "objective>Economics>2020 Model II>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Value - in- Exchange means</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the power of a good to exchange other goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">utility to exchange the price of goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the worth of an individual of a good  or service</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it must possess satisfaction</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Value-in-exchange refers to the power of a good to exchange other goods. It is the relative measure of the worth of a good or service in relation to other goods and services. It is determined by the market forces of supply and demand. For example, if a bicycle is worth two pairs of shoes in a market, then the value-in-exchange of the bicycle is two pairs of shoes.</div>", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS"}, {"id": "objective>Economics>2020 Model II>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information below to solve <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">OUTPUT</td><td style=\"border:1px solid black;text-align:center;\"> TP</td><td style=\"border:1px solid black;text-align:center;\"> AP</td><td style=\"border:1px solid black;text-align:center;\"> MP</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\">   -</td><td style=\"border:1px solid black;text-align:center;\"> -</td><td style=\"border:1px solid black;text-align:center;\"> -</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">2</td><td style=\"border:1px solid black;text-align:center;\"> a</td><td style=\"border:1px solid black;text-align:center;\"> 5</td><td style=\"border:1px solid black;text-align:center;\"> 10</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">3</td><td style=\"border:1px solid black;text-align:center;\"> 18</td><td style=\"border:1px solid black;text-align:center;\"> 6</td><td style=\"border:1px solid black;text-align:center;\"> b</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">4</td><td style=\"border:1px solid black;text-align:center;\"> 20</td><td style=\"border:1px solid black;text-align:center;\"> 5</td><td style=\"border:1px solid black;text-align:center;\"> 2</td></tr></table></div> <br/>  <br/> What is the missing figure a?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">11</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">a: (TP) = AP x Q <br/>           =  5 x 2 <br/>            = 10</div>", "topic": "THEORY OF PRODUCTION (2) : CONCEPTS OF PRODUCTION"}, {"id": "objective>Economics>2020 Model II>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> Use the information below to solve <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">OUTPUT</td><td style=\"border:1px solid black;text-align:center;\"> TP</td><td style=\"border:1px solid black;text-align:center;\"> AP</td><td style=\"border:1px solid black;text-align:center;\"> MP</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\">   -</td><td style=\"border:1px solid black;text-align:center;\"> -</td><td style=\"border:1px solid black;text-align:center;\"> -</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">2</td><td style=\"border:1px solid black;text-align:center;\"> a</td><td style=\"border:1px solid black;text-align:center;\"> 5</td><td style=\"border:1px solid black;text-align:center;\"> 10</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">3</td><td style=\"border:1px solid black;text-align:center;\"> 18</td><td style=\"border:1px solid black;text-align:center;\"> 6</td><td style=\"border:1px solid black;text-align:center;\"> b</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">4</td><td style=\"border:1px solid black;text-align:center;\"> 20</td><td style=\"border:1px solid black;text-align:center;\"> 5</td><td style=\"border:1px solid black;text-align:center;\"> 2</td></tr></table></div>What is the value of b?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> the value of b \t <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">b(MR)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">∆TC<hr size=\"1\" />∆Q</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">18-10<hr size=\"1\" />3-2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">8</td><td style=\"text-align:center;\"></td></tr></table></div></div>", "topic": "THEORY OF PRODUCTION (2) : CONCEPTS OF PRODUCTION"}, {"id": "objective>Economics>2020 Model II>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a teacher becomes a trader, the type of mobility is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">geographical mobility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vertical mobility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">horizontal mobility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Occupational mobility</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This type of mobility refers to the ability of workers to switch from one occupation or job to another. It involves changes in the kind of work a person does, often requiring new skills or training.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : INTRODUCTION"}, {"id": "objective>Economics>2020 Model II>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a person left his job willingly in search of other payment, it is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">structural unemployment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">frictional unemployment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">seasonal unemployment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">voluntary unemployment</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Voluntary unemployment refers to a situation where a person leaves his job willingly in search of other employment or better pay. This is different from structural unemployment which is caused by a mismatch between the skills that workers in the economy can offer, and the skills demanded of workers by employers. Frictional unemployment is temporary unemployment arising from the process of matching workers with jobs. Seasonal unemployment occurs when people are unemployed at certain times of the year because they work in industries where they are not needed all year round.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT"}, {"id": "objective>Economics>2020 Model II>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main cannons of tax are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Simplicity, flexibility, elasticity and equity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Equality, certainty, convenience and economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Productivity, neutrality, equality and certainty</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Equality, simplicity, equity and certainty</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The first set of principle of taxation was enunciated by Adam smith which he called canons of taxation in 1776. The canons of taxation are: Equality, certainty, convenience and economy.</div>", "topic": "PUBLIC FINANCE : PRINCIPLE OF TAXATION"}, {"id": "objective>Economics>2020 Model II>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">As industrialisation increases, the total output of an economy will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remain constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fluctuate</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">As industrialisation proceeds. the total output of the industrial sector, as a percentage of national output increases.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>2020 Model II>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Green Revolution was set up to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Encourage large farming</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Establish fund to the farmers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Encourage youth to farm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Facilitate agricultural product</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Green Revolution was set up to facilitate agricultural productivity. It was a period when agriculture in India increased its yields due to improved agronomic technology. Green Revolution allowed developing countries, like India, to overcome poor agricultural productivity.</div>", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION"}, {"id": "objective>Economics>2020 Model II>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ways of financing economic development in Nigeria include all except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Borrowing from friends</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Internal borrowing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Debt conversion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Aids and Grants</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The ways of financing economic development in Nigeria are: <br/> - Internal borrowing e.g form bank <br/> - Privatisation and commercialisation of government- owned business enterprises. <br/> - Revenue generated form investment <br/> - Debt conversion <br/> - Government savings and reserve <br/> - Loans from international financial institutions e,g IMF, World Bank <br/> - Aids and grants</div>", "topic": "ECONOMIC DEVELOPMENT : DEVELOPMENT PLANNING"}, {"id": "objective>Economics>2020 Model II>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">IMF was established to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Stabilise exchange rate among members countries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Provide training for expert</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Remove obstacle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Adopt a common policy transport</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">International Monetary Fund was set up after the second world war in 1947 in order to encourage the development of foreign trade.</div>", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : OPEC, ECA, IMF"}, {"id": "objective>Economics>2020 Model II>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Maximum price control is fixed by the government in order to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">protect the buyer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protect the producer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protect the seller</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protect the market</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A maximum price or price ceiling is a legal price set below the equilibrium market price above which a seller cannot charge for a product. It is set to safeguard consumers when the equilibrium market price for a commodity is found to be unfairly high. Maximum prices are normally set for essential goods such as pharmaceutical drugs or services such as house rental. When a maximum price is set for a good it increases the quantity demanded while the quantity supplied decreases thereby resulting in persistent excess demand or shortage of the good.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : PRICE LEGISLATION"}, {"id": "objective>Economics>2020 Model II>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria economy is a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Capitalist economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Socialist economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Command economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mixed economy</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Nigeria economy is a mixed economy in which the means of production is controlled by an individual and the states (government).</div>", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM"}, {"id": "objective>Economics>2020 Model II>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The effect of minimum wage is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It leads to unemployment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It leads to scarcity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It leads to profit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It decrease price</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Minimum wage is the wage that a worker's pay is not allowed to fall below a given amount. The effect of minimum wages are: <br/> - unemployment <br/> - reduce national income of a country <br/> - there will be rise in the cost and price</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT"}, {"id": "objective>Economics>2020 Model II>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The above diagram represents <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">An increase in demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">An increase in quantity demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A decrease in demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A decrease in quantity demand</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">There is an increase in the demand curve when the curve shifts to the right( upward or outward). The curve shift from D1D1 to D2D2 and the quantity increase from Q1 to Q2.</div>", "topic": "THE THEORY OF DEMAND : DISTINCTION BETWEEN CHANGE IN QUANTITY DEMANDED AND CHANGE IN DEMAND"}, {"id": "objective>Economics>2020 Model II>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the two goods are perfect complementary, the indifference curve is a  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Straight line</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Right-angled</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Curvature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Left-angled</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If the two goods are perfect complementary, the difference curve is right angled as shown below <br/> <img src=\"2020 Model II/utme2020md2q42.png\" style=\"position:relative;max-width:100%;\"/> <br/> </div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : INDIFFERENCE CURVE"}, {"id": "objective>Economics>2020 Model II>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The curve III represents <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Progressive tax</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Proportional tax</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Regressive tax</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Digressive tax</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Curve III above represent Regressive tax as shown in the diagram above.</div>", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX"}, {"id": "objective>Economics>2020 Model II>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> From the diagram above, The minimum wage rate is <br/>  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">W3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">W2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">W0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">W1</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The minimum wage is always above the equilibrium wage rate. At W1, there is minimum wage where the supply of labour exceeds the demand for labour.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT"}, {"id": "objective>Economics>2020 Model II>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The curve II is the <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">TC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">MC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">VC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">FC</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The curve II represent the variable cost as shown in the diagram above.</div>", "topic": "THE CONCEPT OF COST & REVENUE : THE MARGINAL COST & SUPPLY CURVE OF A FIRM"}, {"id": "objective>Economics>2020 Model II>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">price (#)</td><td style=\"border:1px solid black;text-align:center;\"> Qty(bags)</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">2</td><td style=\"border:1px solid black;text-align:center;\">60</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">4</td><td style=\"border:1px solid black;text-align:center;\">100</td></tr></table></div> <br/>  <br/> Calculate the price elasticity of supply from the table above</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.6</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">es = ∆Qd/ ∆P    x P/Qd <br/>  <br/> ∆Qd = Q2 - Q1 <br/> ∆P = P2 - P1 <br/> P = P1 <br/> Qd = Q1 <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">e</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">100 - 60<hr size=\"1\" />4 - 2</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">2<hr size=\"1\" />60</td></tr></table></div> <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">40<hr size=\"1\" />2</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">2<hr size=\"1\" />60</td></tr></table></div> <br/>  <br/> = 0.6</div>", "topic": "THE THEORY OF SUPPLY"}, {"id": "objective>Economics>2020 Model II>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a producer sells 1kg of rice for ₦20 and his marginal products is 100kg, what is the highest wage he can pay the marginal labourer?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> ₦ 20.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> ₦. 50.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> ₦ 100.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> ₦ 200.00</div>"], "answer": -1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To determine the highest wage the producer can pay the marginal laborer, you can use the concept of marginal product and the marginal revenue product of labor. <br/>  <br/> The marginal revenue product of labor (MRP) is the additional revenue generated by employing one more unit of labor. In this case, the marginal product is given as 100kg. <br/>  <br/> If the producer sells 1kg of rice for ₦20, then the additional revenue from the marginal product is: <br/>  <br/> MRP = Price × Marginal Product <br/> = ₦20/kg × 100kg <br/> = ₦2000 <br/>  <br/> So, the highest wage the producer can pay the marginal laborer is ₦2000.</div>", "topic": "THEORY OF COST AND REVENUE"}, {"id": "objective>Economics>2020 Model II>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Public expenditure creates expansionary effects in the economy when its is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">in excess of government revenue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">channeled into capital projects</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diverted into imports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">financed through oil revenue</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Expansionary fiscal policy is a policy that involves increasing government spending or decreasing taxes in order to stimulate the economy. When the government spends more money than it receives in revenue, it creates a budget deficit. This deficit can be financed through borrowing, which puts more money into the economy and can lead to increased economic activity.</div>", "topic": "PUBLIC FINANCE"}, {"id": "objective>Economics>2020 Model II>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>Use the table below to answer the question</strong> <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Variable factor</td><td style=\"border:1px solid black;text-align:center;\"> Total product</td><td style=\"border:1px solid black;text-align:center;\"> Marginal Product</td><td style=\"border:1px solid black;text-align:center;\"> Average Product</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\">1</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">2</td><td style=\"border:1px solid black;text-align:center;\">6</td><td style=\"border:1px solid black;text-align:center;\">5</td><td style=\"border:1px solid black;text-align:center;\">3</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">3</td><td style=\"border:1px solid black;text-align:center;\">24</td><td style=\"border:1px solid black;text-align:center;\">18</td><td style=\"border:1px solid black;text-align:center;\">8</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">4</td><td style=\"border:1px solid black;text-align:center;\">48</td><td style=\"border:1px solid black;text-align:center;\"> X</td><td style=\"border:1px solid black;text-align:center;\"> 12</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">5</td><td style=\"border:1px solid black;text-align:center;\">Z</td><td style=\"border:1px solid black;text-align:center;\">25</td><td style=\"border:1px solid black;text-align:center;\">14.6</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">6</td><td style=\"border:1px solid black;text-align:center;\">93</td><td style=\"border:1px solid black;text-align:center;\">20</td><td style=\"border:1px solid black;text-align:center;\">Y</td></tr></table></div> <br/>  <br/> The marginal product X is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">18</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20</div>", "<div style=\"font-family:Cambria;font-size:17px;\">24</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To calculate the marginal product, we use the formular:  Change in TP/Change in variable factor <br/>  <br/> = 48 - 24/ 4 - 3 <br/>  <br/> X = 24</div>", "topic": "THE THEORY OF PRODUCTION"}, {"id": "objective>Economics>2020 Model II>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">To assure that the non price determinant of demand and supply were not ignored, we use assumption of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Demand and supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Equilibrium price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Constant supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Other thing being equal</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The assumption that is used to assure that the non-price determinants of demand and supply are not ignored is ceteris paribus, which means all other things being equal. This assumption is used to isolate the effect of one variable on another, such as the effect of price on quantity demanded. <br/>  <br/> When we use the ceteris paribus assumption, we are saying that all other factors that affect demand and supply are held constant. This allows us to focus on the relationship between price and quantity demanded or price and quantity supplied.</div>", "topic": "THE THEORY OF DEMAND"}, {"id": "objective>Economics>2020 Model II>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the following classical economist propounded the theory of population</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Thomas Robert Malthus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Adam Smith</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Alfred Marshal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">All of the above</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Malthus is best known for his work \"An Essay on the Principle of Population,\" in which he discussed the relationship between population growth and its consequences for society and resources. Adam Smith and Alfred Marshall made significant contributions to economics, but they are not specifically known for theories of population as Malthus is.</div>", "topic": "POPULATION"}, {"id": "objective>Economics>2020 Model II>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Consumer surplus means</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">excess expenditure over revenue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excess expenditure over utility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excess revenue over expenditure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excess utility over expenditure</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Consumer surplus is a concept in economics that represents the difference between what a consumer is willing to pay for a good or service (indicated by their demand curve) and what they actually pay. It is essentially the benefit or satisfaction that consumers derive from paying a price that is less than the maximum price they are willing to pay. In other words, consumer surplus is the excess of the perceived value or utility of a good over the actual price paid for it.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER SURPLUS"}, {"id": "objective>Economics>2020 Model II>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The account that shows the actual transfer of money from one country to the other is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">capital account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">foreign account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">foreign exchange account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">domiciliary account</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The account that shows the actual transfer of money from one country to the other is called the capital account. <br/>  <br/> Foreign account is a bank account that is held in a foreign currency. <br/> Foreign exchange account is a bank account that is used to exchange one currency for another. <br/> Domiciliary account is a bank account that is held in the name of a non-resident but is managed by a bank in the resident country. <br/>  <br/> The capital account records all of the transactions that involve the transfer of ownership of assets between countries. This includes investments, loans, and gifts. The capital account is important because it shows how much money is flowing into and out of a country. This can affect the exchange rate and the overall economy.</div>", "topic": "INTERNATIONAL TRADE"}, {"id": "objective>Economics>2020 Model II>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements must hold if price discrimination is to be possible?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Elasticity in the various markets must not differ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The seller must recognize the possibility of resale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The market must not be separated but integrated</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The market should be separated and there should be no resale</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Price discrimination occurs when a seller charges different prices for the same product or service to different groups of customers or in different markets. To successfully implement price discrimination, the seller often tries to prevent or minimize resale of the product or service between different customer groups or markets. This separation and restriction on resale allow the seller to charge different prices based on the willingness and ability to pay of each customer group without arbitrage opportunities. <br/>  <br/> However, the following must occur for price discrimination to take place: <br/> - the elasticity must be different <br/> - consumer ignorance <br/> - the market must be seperated</div>", "topic": "MARKET STRUCTURE"}, {"id": "objective>Economics>2020 Model II>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>Use the diagram below to answer the question</strong> <br/>  <br/> The diagram explains the effects of government imposition of indirect tax on a good characterized by zero price elasticity of demand. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> A total tax revenue is represented by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">I</span>EHP<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span>HQ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">I</span>EQ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span>OO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">I</span>ED<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">I</span>P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The total tax revenue is represented by PIEHPo. <br/>  <br/> When the government imposes an indirect tax on a good with zero price elasticity of demand, the entire burden of the tax is borne by the consumers. This is because the consumers have no substitutes for the good and are therefore willing to pay the higher price in order to obtain the good. <br/>  <br/> The diagram shows the effects of the indirect tax on the market for the good. The demand curve is perfectly inelastic, which means that the quantity demanded of the good remains the same even when the price of the good increases. <br/>  <br/> The supply curve is upward sloping, which means that the quantity supplied of the good increases as the price of the good increases. <br/>  <br/> When the government imposes the indirect tax, the price of the good increases from Po to P1. The quantity demanded of the good remains the same at Qo. <br/>  <br/> The total tax revenue is equal to the amount of the tax per unit multiplied by the quantity of the good sold. In this case, the tax per unit is equal to the difference between the new price of the good (P1) and the old price of the good (Po). The quantity of the good sold is equal to Qo. <br/>  <br/> Therefore, the total tax revenue is equal to (P1 - Po) x Qo = PIEHPo.</div>", "topic": "THE THEORY OF PRICE DETERMINATION"}, {"id": "objective>Economics>2020 Model II>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Capital provided by individuals to the firm by purchasing stocks is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">debt capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fixed capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">circulating capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equity capital</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The answer is Equity capital: This  is the money that is raised by a company by selling shares of ownership to investors. Investors who purchase shares of stock become shareholders in the company and are entitled to a share of the company's profits. <br/>  <br/>  <br/> Debt capital is money that is borrowed by a company from a lender, such as a bank. The lender expects to be repaid the borrowed money, plus interest, over a specified period of time. <br/>  <br/> Fixed capital is the long-term assets of a company, such as buildings, machinery, and equipment. Fixed capital is used to produce goods and services. <br/>  <br/> Circulating capital is the short-term assets of a company, such as inventory and accounts receivable. Circulating capital is used to finance the day-to-day operations of the company. <br/> </div>", "topic": "BUSINESS ORGANIZATIONS"}, {"id": "objective>Economics>2020 Model II>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">National debt is an expected outcome of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">consolidated budget</div>", "<div style=\"font-family:Cambria;font-size:17px;\">balanced budget</div>", "<div style=\"font-family:Cambria;font-size:17px;\">deficit budget</div>", "<div style=\"font-family:Cambria;font-size:17px;\">surplus budget</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a government runs a deficit budget, it means that its expenditures exceed its revenues in a given fiscal year. To cover this deficit, the government typically borrows money by issuing bonds or taking out loans. Over time, the accumulated deficits and borrowing lead to a national debt. This debt represents the total amount of money that the government owes to creditors, including both domestic and foreign lenders. So, running deficit budgets is a common way in which national debt is accumulated.</div>", "topic": "PUBLIC FINANCE"}];
